export const getMarketData = async () => {
    // CollectAPI.com üzerinden aldığınız şifreyi aşağıdaki tırnak içine yazın.
    // Örnek: "apikey 1a2b3c4d5e...:1a2b3c4d5e..." (apikey yazısı kalacak, gerisi sizin şifreniz)
    const API_KEY = "apikey BURAYA_KAYIT_OLUP_ALACAGINIZ_SIFREYI_YAZIN";

    // Güvenli ve gerçekçi veriler için hem altın hem de döviz bağlantıları
    const goldUrl = "https://api.collectapi.com/economy/goldPrice";
    const currencyUrl = "https://api.collectapi.com/economy/allCurrency";

    try {
        // CollectAPI zorunlu güvenlik doğrulama bilgileri
        const options = {
            method: 'GET',
            headers: {
                'authorization': API_KEY,
                'content-type': 'application/json'
            }
        };

        // Eğer henüz API key girilmemişse sistemi çökertmemek için geçici veri dönüyoruz
        if (API_KEY.includes("KAYIT_OLUP_ALACAGINIZ_SIFREYI_YAZIN")) {
            console.warn("Lütfen CollectAPI şifrenizi marketService.js dosyasına girin.");
            return [{ symbol: "Sistem", price: "API Şifresi Bekleniyor...", trend: "down" }];
        }

        // İki farklı API isteğini (Altın ve Döviz) aynı anda yapıyoruz ki site beklemesin
        const [goldResponse, currencyResponse] = await Promise.all([
            fetch(goldUrl, options),
            fetch(currencyUrl, options)
        ]);

        const goldData = await goldResponse.json();
        const currencyData = await currencyResponse.json();

        // 1. Gelen tüm altın verilerini döngüyle tarayıp istediğimiz sembolleri yakalıyoruz
        const formattedGold = goldData.result
            .filter(item => ["Gram Altın", "Çeyrek Altın", "Cumhuriyet Altını", "Ons"].includes(item.name))
            .map(item => ({
                symbol: item.name.toUpperCase(),
                price: item.name === "Ons" ? `$${item.selling.toFixed(2)}` : `₺${item.selling.toFixed(2)}`,
                trend: item.rate > 0 ? 'up' : 'down'
            }));

        // 2. Gelen tüm döviz verilerini tarayıp asıl para birimlerimizi alıyoruz
        const formattedCurrency = currencyData.result
            .filter(item => ["USD", "EUR", "GBP"].includes(item.code))
            .map(item => ({
                symbol: `${item.code}/TRY`,
                price: `₺${item.selling.toFixed(2)}`,
                trend: item.rate > 0 ? 'up' : 'down'
            }));

        // İki veriyi şık bir şekilde birleştirip Return (dışarıya) aktarıyoruz
        return [...formattedCurrency, ...formattedGold];

    } catch (error) {
        console.error("Yasal API limitlerine takılmış olabilirsiniz veya bağlantı hatası:", error);
        return [{ symbol: "Hata", price: "Bağlantı Sorunu", trend: "down" }];
    }
};
